CREATE OR REPLACE FUNCTION OFSERM.CAP_MKT_RISK_REPORTING_POP_IR(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FCT_MARKET_RISK_REPORTING(V_CCY_CODE,N_MIS_DATE_SKEY,N_REP_LINE_SKEY,N_RUN_SKEY,N_COUNTRY_SKEY,N_NET_HORIZONTAL_DISALLOWANCE,N_NET_VERTICAL_DISALLOWANCE,N_OFFST_MW_TB_POS,N_OFFST_MW_TB_RW,N_OFFST_MZ_ONE_TWO_POS,N_OFFST_MZ_ONE_TWO_RW,N_OFFST_MW_ZONE_ONE_RW,N_OFFST_MW_ZONE_THREE_POS,N_OFFST_MW_ZONE_THREE_RW,N_OFFST_MW_ZONE_TWO_POS,N_OFFST_MW_ZONE_TWO_RW,N_OFFST_MZ_ONE_THREE_POS,N_OFFST_MZ_ONE_THREE_RW,N_OFFST_MZ_TWO_THREE_POS,N_OFFST_MZ_TWO_THREE_RW,N_OFFST_MW_ZONE_ONE_POS,N_OVERALL_NET_POS,N_OVERALL_NET_POS_RW,V_APPROACH_TYPE,V_COMMODITY_GROUP_CODE)SELECT  /*+PARALLEL (4)*/ DIM_CURRENCY.V_ISO_CURRENCY_CD,to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_MARKET_RISK_REP_LINE.N_REP_LINE_SKEY),to_char(DIM_RUN.N_RUN_SKEY),((SELECT n_country_skey from DIM_COUNTRY WHERE v_country_id = 'US' AND DIM_DATES.D_CALENDAR_DATE BETWEEN D_RECORD_START_DATE AND D_RECORD_END_DATE)),SUM(COALESCE(FCT_MARKET_RISK_CAPITAL.N_OFFST_MATCH_WITHIN_ZONE,0) * CASE WHEN DIM_TIME_ZONE.V_TIME_ZONE_CODE = 'Z1' THEN 0.4 WHEN DIM_TIME_ZONE.V_TIME_ZONE_CODE IN ('Z2','Z3') THEN 0.3 ELSE 0 END) + SUM(COALESCE(FCT_MARKET_RISK_CAPITAL.N_OFFST_MATCH_ADJCNT_ZONE,0) * CASE WHEN DIM_TIME_ZONE.V_TIME_ZONE_CODE IN ('Z1','Z2','Z3') THEN 0.4 ELSE 0 END) + SUM(COALESCE(FCT_MARKET_RISK_CAPITAL.N_OFFST_MATCH_NONADJCNT_ZONE,0) * CASE WHEN DIM_TIME_ZONE.V_TIME_ZONE_CODE IN ('Z1','Z3') THEN 1 ELSE 0 END) + SUM(COALESCE(FCT_MARKET_RISK_CAPITAL.N_OFFST_UNMATCH_NONADJCNT_ZONE,0)),SUM(COALESCE(FCT_MARKET_RISK_CAPITAL.N_WEIGHTED_LONG_POSITION_AMT,0) + COALESCE(FCT_MARKET_RISK_CAPITAL.N_WEIGHTED_SHORT_POSITION_AMT,0)) * 0.05,SUM(n_offst_match_within_tb),MAX(CASE WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'DBN%' THEN (SELECT v_param_value FROM REVELEUS_PARAMETER_MASTER WHERE v_param_code = 'IDVD') WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'IRBN%' THEN (SELECT v_param_value FROM REVELEUS_PARAMETER_MASTER WHERE v_param_code = 'IMVD') END),SUM(CASE WHEN DIM_MR_TIME_BAND.v_band_sub_category IN ('DBND5', 'IRBN5') THEN n_offst_match_adjcnt_zone ELSE 0 END),MAX(CASE WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'DBN%' THEN (SELECT v_param_value FROM REVELEUS_PARAMETER_MASTER WHERE v_param_code = 'IDHDZ12') WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'IRBN%' THEN (SELECT v_param_value FROM REVELEUS_PARAMETER_MASTER WHERE v_param_code = 'IMHDZ12') END),MAX(CASE WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'DBN%' THEN (SELECT v_param_value FROM REVELEUS_PARAMETER_MASTER WHERE v_param_code = 'IDHDZ1') WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'IRBN%' THEN (SELECT v_param_value FROM REVELEUS_PARAMETER_MASTER WHERE v_param_code = 'IMHDZ1') END),SUM(CASE WHEN DIM_MR_TIME_BAND.v_band_sub_category IN ('DBND8', 'IRBN8') THEN n_offst_match_within_zone ELSE 0 END),MAX(CASE WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'DBN%' THEN (SELECT v_param_value FROM REVELEUS_PARAMETER_MASTER WHERE v_param_code = 'IDHDZ3') WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'IRBN%' THEN (SELECT v_param_value FROM REVELEUS_PARAMETER_MASTER WHERE v_param_code = 'IMHDZ3') END),SUM(CASE WHEN DIM_MR_TIME_BAND.v_band_sub_category IN ('DBND5', 'IRBN5') THEN n_offst_match_within_zone ELSE 0 END),MAX(CASE WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'DBN%' THEN (SELECT v_param_value FROM REVELEUS_PARAMETER_MASTER WHERE v_param_code = 'IDHDZ2') WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'IRBN%' THEN (SELECT v_param_value FROM REVELEUS_PARAMETER_MASTER WHERE v_param_code = 'IMHDZ2') END),SUM(CASE WHEN DIM_MR_TIME_BAND.v_band_sub_category IN ('DBND8', 'IRBN8') THEN n_offst_match_nonadjcnt_zone ELSE 0 END),MAX(CASE WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'DBN%' THEN (SELECT v_param_value FROM REVELEUS_PARAMETER_MASTER WHERE v_param_code = 'IDHDZ31') WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'IRBN%' THEN (SELECT v_param_value FROM REVELEUS_PARAMETER_MASTER WHERE v_param_code = 'IMHDZ31') END),SUM(CASE WHEN DIM_MR_TIME_BAND.v_band_sub_category IN ('DBND8', 'IRBN8') THEN n_offst_match_adjcnt_zone ELSE 0 END),MAX(CASE WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'DBN%' THEN (SELECT v_param_value FROM REVELEUS_PARAMETER_MASTER WHERE v_param_code = 'IDHDZ32') WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'IRBN%' THEN (SELECT v_param_value FROM REVELEUS_PARAMETER_MASTER WHERE v_param_code = 'IMHDZ32') END),SUM(CASE WHEN DIM_MR_TIME_BAND.v_band_sub_category IN ('DBND1', 'IRBN1') THEN n_offst_match_within_zone ELSE 0 END),SUM(CASE WHEN DIM_MR_TIME_BAND.v_band_sub_category IN ('DBND1', 'IRBN1','DBND8', 'IRBN8') THEN n_offst_unmatch_nonadjcnt_zone WHEN DIM_MR_TIME_BAND.v_band_sub_category IN ('DBND5', 'IRBN5') THEN n_offst_unmatch_adjcnt_zone ELSE 0 END),MAX(CASE WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'DBN%' THEN (SELECT v_param_value FROM REVELEUS_PARAMETER_MASTER WHERE v_param_code = 'IDON') WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'IRBN%' THEN (SELECT v_param_value FROM REVELEUS_PARAMETER_MASTER WHERE v_param_code = 'IMON') END),MAX(CASE WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'DBN%' THEN 'DUR' WHEN DIM_MR_TIME_BAND.v_band_sub_category like 'IRBN%' THEN 'MAT' END),'NA' FROM FCT_MARKET_RISK_CAPITAL LEFT OUTER JOIN DIM_BANDS DIM_MR_TIME_BAND ON FCT_MARKET_RISK_CAPITAL.n_time_band_skey = DIM_MR_TIME_BAND.n_band_skey AND DIM_MR_TIME_BAND.v_Band_Type = 'MR TIME BAND' LEFT OUTER JOIN DIM_DATES ON FCT_MARKET_RISK_CAPITAL.n_mis_date_skey = DIM_DATES.N_DATE_SKEY LEFT OUTER JOIN DIM_RUN ON FCT_MARKET_RISK_CAPITAL.n_run_skey = DIM_RUN.n_run_skey LEFT OUTER JOIN DIM_BASEL_METHODOLOGY ON FCT_MARKET_RISK_CAPITAL.n_basel_method_skey = DIM_BASEL_METHODOLOGY.n_basel_method_skey LEFT OUTER JOIN DIM_CURRENCY ON FCT_MARKET_RISK_CAPITAL.v_ccy_code = DIM_CURRENCY.v_iso_currency_cd LEFT OUTER JOIN DIM_GAAP ON FCT_MARKET_RISK_CAPITAL.n_gaap_skey = DIM_GAAP.n_gaap_skey LEFT OUTER JOIN DIM_COUNTRY ON FCT_MARKET_RISK_CAPITAL.n_country_skey = DIM_COUNTRY.n_country_skey LEFT OUTER JOIN DIM_MARKET_RISK_REP_LINE ON FCT_MARKET_RISK_CAPITAL.n_rep_line_skey = DIM_MARKET_RISK_REP_LINE.n_rep_line_skey LEFT OUTER JOIN DIM_TIME_ZONE ON DIM_TIME_ZONE.N_TIME_ZONE_SKEY = FCT_MARKET_RISK_CAPITAL.N_TIME_ZONE_SKEY WHERE 1=1 AND 1=1 AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') AND FCT_MARKET_RISK_CAPITAL.n_run_skey = '870' AND DIM_MARKET_RISK_REP_LINE.v_rep_line_code IN ('IR', 'IRAFS', 'IRHFT') AND (DIM_MR_TIME_BAND.v_band_Sub_category like 'DBN%' OR DIM_MR_TIME_BAND.v_Band_Sub_Category like 'IRBN%') GROUP BY DIM_DATES.N_DATE_SKEY, DIM_DATES.D_CALENDAR_DATE, DIM_RUN.n_run_skey, DIM_CURRENCY.v_iso_currency_cd, DIM_MARKET_RISK_REP_LINE.n_rep_line_skey, DIM_COUNTRY.n_country_skey LOG ERRORS INTO FCT_MARKET_RISK_REPORTING$ ('1776769809014_18600978_20260331_1_Job_cf84bd3f62834db7a58d1d0575cb131e') REJECT LIMIT 0;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
